import pickle
def to_file(pref):
    with open('pref.txt', 'w+') as fout:
        pref = pickle.dump(pref, fout)
def from_file():
    try:
        with open('pref.txt') as fin:
            return pickle.load(fin)
    except (OSError, ValueError):
        pass

